form:Form.form:Scripts:
		var numPage, maxPage, isSync;

function EnableBottons()
{
	 if (numPage==0)
	 {
			CtrlEnabled("btnFirst", false);
			CtrlEnabled("btnPrev" , false);
	 } else
	 {
			CtrlEnabled("btnFirst", true );
			CtrlEnabled("btnPrev" , true );
	 } 
	 if (numPage==maxPage)
	 {
			CtrlEnabled("btnNext", GetRow("19").GetAttr("EST")==""?false:true);
			CtrlEnabled("btnLast", false);
	 } else
	 {                            
			CtrlEnabled("btnNext", true);
			CtrlEnabled("btnLast", true );
	 }    

	 if (isSync)
	 {
			CtrlEnabled("btnDownload", true );
	 } else
	 {
			CtrlEnabled("btnDownload", false);
	 }
}

function OnLoad()
{ 
  Page=Ctrl("main").GetLastDocXML("PAGE");
  numPage=parseInt(Ctrl("numpage").GetXValue(),10);
  maxPage=parseInt(Ctrl("maxpage").GetXValue(),10)-1;

  isSync=true;
  EnableBottons();
	Ctrl("PAGINA_INTERFAZ").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusRH.Base.Tiempos_Trabajados.NovedadesGrilla.rpt&now="+(new Date()).toString());
}      

function GetRow(id)
{                 
	return Ctrl("rows").GetRow(parseInt(id,10));
}                           

function OnLostFocusEmpresa(id, value)
{                  
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("EMP");
	var newVal=value;

	//Actualize el VALOR           
	myROW.SetAttr("EMP",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		myROW.SetAttr("EMP_DESC","..."); //Descriptcion Desconocida
		isSync=false; 
		EnableBottons();
	}
}


function OnLostFocusLegajo(id, value)
{                  
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("LEG");
	var newVal=parseInt(value,10); if (isNaN(newVal)) newVal=""; 
	                                             else newVal=newVal.toString();
	//Actualize el VALOR           
	myROW.SetAttr("LEG",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		myROW.SetAttr("LEG_DESC","..."); //Descriptcion Desconocida
		isSync=false; 
		EnableBottons();
	}
}

function OnLostFocusHorario(id, value)
{	
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("HOR");
	var newVal=Trim(value); 

	//Actualize el VALOR           
	myROW.SetAttr("HOR",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		myROW.SetAttr("HOR_DESC","..."); //Descriptcion Desconocida

		isSync=false; 
		EnableBottons();
	}
}

function ValidarFecha(tipo,id,value)
{            
    myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr(tipo);
	var newVal=Trim(value); 

	if (newVal!="")
	{  
		var year=0, month=0, day=0;

		if (newVal.toUpperCase()=="HOY")
		{       
			year =Now().getFullYear();
			month=Now().getMonth()+1;
			day  =Now().getDate();
		} 
		else
		if ((newVal.indexOf("-")>=0) || (newVal.indexOf("/")>=0))
		{
			var aValue;      

			if (newVal.indexOf("-")>=0)
				aValue=newVal.split('-');
			else 
				aValue=newVal.split('/');

			if (aValue.length==3)
			{
				year =parseInt(aValue[2],10);
				month=parseInt(aValue[1],10);
				day  =parseInt(aValue[0],10);
			}
			else if (aValue.length==2)
			{         
				year =Now().getFullYear();
				month=parseInt(aValue[1],10);
				day  =parseInt(aValue[0],10);
			} 
			else
				year=0;

			if (month==0 && aValue.length>=2)
			{         
				month="|ENE|FEB|MAR|ABR|MAY|JUN|JUL|AGO|SEP|OCT|NOV|DIC|".indexOf("|"+aValue[1].toUpperCase()+"|");
				if (month==-1)
					year=0;
				else     
					month=month/4+1;
			}    

			var retornoMin = 0;
			var retornoHoras = 0;
			if(newVal.indexOf(" ")>=0)
			{        
				var horas;
				var minutos;

				var horas = newVal.split(" ")[1];
				if (horas.indexOf(":")>=0)
				{ //HH:SS
					hora =parseInt(horas.split(":")[0],10); 
					if (!isNaN(hora) && ((horas.split(":")[0]).length == 2 || (horas.split(":")[0]).length == 1))  
					{                             
						minutos = parseInt(horas.split(":")[1],10);  
						if (!isNaN(minutos) && (horas.split(":")[1]).length == 2) 
						{ 
							if(minutos >=0 && minutos <=59 && hora >=0 && hora <=23)
							{      
								retornoHoras = hora;           
								retornoMin = minutos;
							}  	 
						} 
					}  
				} 	
			}

		}

		if (year==0)
			value="";
		else
		{
			if (year<50)
			{       
				year+=2000;
			}
			else if (year<100)
			{           
				year+=1900;
			}     

			var mes=month-1;
   			// Establecemos un objeto Data con los valore recibidos
   			var dteDate=new Date(year,mes,day,retornoHoras,retornoMin);  
   		    var m = dteDate.getMonth();
   		    var d = dteDate.getDate();
   		    var y = dteDate.getFullYear();  
   		    var h = dteDate.getHours();  
   		    var min = dteDate.getMinutes();
			if ((day==dteDate.getDate()) && (mes==dteDate.getMonth()) && (year==dteDate.getFullYear()))
			{
				value=(day+month*100+year*10000).toString();
				value=value.substr(6,2)+"/"+value.substr(4,2)+"/"+value.substr(0,4)+" "+h.toString().padStart(2,'0')+":"+min.toString().padStart(2,'0');			 				
			}
			else
			{
				value = "";
			}
		}		



  	}

  	//Actualize el VALOR           
	myROW.SetAttr(tipo,value);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST","1"); //Modificado
		isSync=false; 
		EnableBottons();
	}       
}
function OnLostFocusFechaDesde(id, value)
{	
	 ValidarFecha("FECDESDE",id,value);	
}   

function OnLostFocusFechaHasta(id, value)
{	 
	 ValidarFecha("FECHASTA",id,value);
}

