function CleanRow(id)
{
	myROW=GetRow(id);
	if (myROW==null) return;
	if (myROW.GetAttr("EST")=="") return;

	//Cambio el Estado
	myROW.SetAttr("EST","1");
	isSync=false; 
	EnableBottons();  

	//Limpio los Registros    
	myROW.SetAttr("EMP","");
	myROW.SetAttr("EMP_DESC","");
	myROW.SetAttr("LEG","");
	myROW.SetAttr("LEG_DESC","");
	myROW.SetAttr("HOR","");
	myROW.SetAttr("HOR_DESC","");
	myROW.SetAttr("FECDESDE","");
	myROW.SetAttr("FECHASTA","");
	//myROW.SetAttr("HDESDE","");
	//myROW.SetAttr("HHASTA","");
	myROW.SetAttr("DES","");
	myROW.SetAttr("OBS","");
	myROW.SetAttr("ERR","");
}

function Refresh()
{ 
	if(Ctrl("oi_terminal").GetXValue() != "")                               
		Ctrl("main").DoEvent("Refresh");
	else
		alert("La terminal es requerida");
}

function First()
{                                
	if (numPage<=0) return;            

	Ctrl("topage").SetXValue("0");
	Ctrl("main").DoEvent("ToPage");
}

function Prev()
{                                
	if (numPage<=0) return;            

	Ctrl("topage").SetXValue((numPage-1).toString());
	Ctrl("main").DoEvent("ToPage");
}

function Next()
{                                
	Ctrl("topage").SetXValue((numPage+1).toString());
	Ctrl("main").DoEvent("ToPage");
}

function Last()
{    
	if (numPage>=maxPage) return;            

	Ctrl("topage").SetXValue(maxPage.toString());
	Ctrl("main").DoEvent("ToPage");
}

function Download()
{
	DownloadFile("INTERFACES\\"+GetProxy().UserName()+".intvar.xml", "intvar.xml");
}

function ObjectUpload(MyOBJ, fileName)
{
	var retval=MyOBJ;                   
	retval.FileName=fileName;

	retval.processResult= function(xmlin)
	{  
		var proxy=GetProxy(); //as NomadProxy

		//Eliminar el Archivo
		if (proxy.FileSystem().FileExist(".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml"))
			proxy.FileSystem().Delete(".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml");

		//Mover el ARCHIVO
		proxy.FileSystem().Move(".\\Nomad\\Temp\\"+fileName,".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml");

		//Reset
		Ctrl("main").DoEvent("Reset");
	}     
	return retval;
}  

function Upload(MyOBJ)
{
	var arrParams = new Array();
	arrParams[0] = "FOLDER";
	arrParams[1] = "TEMP";
	arrParams[2] = datetime2str(new Date()) + ".intvar.xml";

	showBrowse(ObjectUpload(MyOBJ, datetime2str(new Date()) + ".intvar.xml"), arrParams);
}

